// ========== دوال المساعدة ==========
const shuffleArray = (arr) => {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
};

const trueFalseQuestions = (items) =>
  items.map(([text, correct, hint, reference]) => ({
    type: "صح أو خطأ",
    text,
    answers: shuffleArray(["صح", "خطأ"]),
    correct: (correct === "صح" || correct === "صحيح") ? "صح" : "خطأ",
    hint: hint || "لا يوجد تلميح.",
    reference: reference || "لا يوجد مرجع.",
  }));

const choiceQuestions = (items) =>
  items.map(([text, answers, correct, hint, reference]) => ({
    type: "اختيار من متعدد",
    text,
    answers: shuffleArray([...answers]),
    correct,
    hint: hint || "لا يوجد تلميح.",
    reference: reference || "لا يوجد مرجع.",
  }));

